# Utility module for shape calculations and transformations
from shapes import Rectangle, Circle

def scale_rectangle(rect: Rectangle, factor: float) -> Rectangle:
    """Create a scaled copy of a rectangle"""
    new_width: float = rect.width * factor
    new_height: float = rect.height * rect.height
    return Rectangle(new_width, new_height)

def compare_areas(shape_a_area: float, shape_b_area: float) -> int:
    """Compare two areas, returns -1 if a<b, 0 if equal, 1 if a>b"""
    if shape_a_area < shape_b_area:
        return -1
    elif shape_a_area > shape_b_area:
        return 1
    else:
        return 0

def sum_areas(shapes: list[float]) -> float:
    """Sum a list of area values"""
    total: float = 0.0
    for area in shapes:
        total += area
    return total

class ShapeStats:
    calculations_done: int

    def __init__(self):
        self.calculations_done = 0

    def record_calculation(self):
        self.calculations_done += 1

    def get_count(self) -> int:
        return self.calculations_done
